import asyncio
import random
from enum import Enum


class ErrorClass(Enum):
    TRANSIENT = "transient"   # safe to retry
    PERMANENT = "permanent"   # do not retry; escalate


def classify_error(exc: Exception) -> ErrorClass:
    import httpx
    if isinstance(exc, httpx.TimeoutException):
        return ErrorClass.TRANSIENT
    if isinstance(exc, httpx.HTTPStatusError):
        if exc.response.status_code == 429:
            return ErrorClass.TRANSIENT
        if exc.response.status_code in (400, 401, 403, 404, 422):
            return ErrorClass.PERMANENT
    return ErrorClass.TRANSIENT  # default: assume transient


async def retry_with_backoff(
    fn,
    *args,
    max_attempts: int = 5,
    base_delay: float = 1.0,
    **kwargs,
):
    for attempt in range(max_attempts):
        try:
            return await fn(*args, **kwargs)
        except Exception as exc:
            if classify_error(exc) == ErrorClass.PERMANENT:
                raise  # no retry for permanent errors
            if attempt == max_attempts - 1:
                raise
            delay = base_delay * (2 ** attempt) + random.uniform(0, 0.5)
            await asyncio.sleep(delay)
    raise RuntimeError("unreachable")
